import { Meta } from "@storybook/addon-docs/blocks";
import { T } from "../stories/T";


<Meta title="Token/Breakpoints" />

<h1><T k="token_bp_title" /></h1>
<p><T k="token_bp_desc" /></p>

<hr />

<h2><T k="token_bp_list" /></h2>

<table>
  <thead>
    <tr>
      <th><T k="token_bp_th_key" /></th>
      <th><T k="token_bp_th_width" /></th>
      <th><T k="token_bp_th_device" /></th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td>`sm`</td>
      <td>576px</td>
      <td><T k="token_bp_sm_device" /></td>
    </tr>
    <tr>
      <td>`md`</td>
      <td>768px</td>
      <td><T k="token_bp_md_device" /></td>
    </tr>
    <tr>
      <td>`lg`</td>
      <td>992px</td>
      <td><T k="token_bp_lg_device" /></td>
    </tr>
    <tr>
      <td>`xl`</td>
      <td>1200px</td>
      <td><T k="token_bp_xl_device" /></td>
    </tr>
  </tbody>
</table>

<hr />

<h2><T k="token_bp_scss" /></h2>

<p dangerouslySetInnerHTML={{ __html: "<T k='token_bp_scss_desc' />" }} />

<h3>`@include up($breakpoint)`</h3>
<p dangerouslySetInnerHTML={{ __html: "<T k='token_bp_up_desc' />" }} />

```scss
@use "../../tokens/breakpoints" as *;

.my-component {
  // Default (for small screens like smartphones)
  display: block;

  @include up(md) {
    // Style for screen width 768px and above
    display: flex;
  }
}
```

<h3>`@include down($breakpoint)`</h3>
<p dangerouslySetInnerHTML={{ __html: "<T k='token_bp_down_desc' />" }} />

```scss
@use "../../tokens/breakpoints" as *;

.my-button {
  padding: 16px;

  @include down(sm) {
    // Reduce padding only when screen width is 576px or less
    padding: 8px;
  }
}
```

<hr />

<h2><T k="token_bp_mq_vs_cq_title" /></h2>

<p dangerouslySetInnerHTML={{ __html: "<T k='token_bp_mq_vs_cq_desc' />" }} />

<table>
  <thead>
    <tr>
      <th></th>
      <th><T k="token_bp_mq_label" /></th>
      <th><T k="token_bp_cq_label" /></th>
    </tr>
  </thead>
  <tbody>
    <tr>
      <td><strong><T k="token_bp_decision_col" /></strong></td>
      <td><T k="token_bp_mq_criterion" /></td>
      <td><T k="token_bp_cq_criterion" /></td>
    </tr>
    <tr>
      <td><strong><T k="doc_real_world_scenarios_title" /></strong></td>
      <td><T k="token_bp_mq_examples" /></td>
      <td><T k="token_bp_cq_examples" /></td>
    </tr>
  </tbody>
</table>

<h3><T k="token_bp_cq_why_title" /></h3>

<p><T k="token_bp_cq_why_desc" /></p>

<h3><T k="token_bp_cq_usage_title" /></h3>

<p dangerouslySetInnerHTML={{ __html: "<T k='token_bp_cq_usage_desc' />" }} />

```scss
@use "../../tokens/breakpoints" as *;

.wim-my-component {
  container-type: inline-size;

  // Narrow layout when container is 768px or less
  @include container-down(md) {
    .wim-my-component__fields {
      flex-direction: column;
    }
  }
}
```

<p><T k="token_bp_cq_note" /></p>

